import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import Navbar from "../components/Navbar";
import Footer from "../components/Footer";
import FavoriteButton from "../components/FavoriteButton";
import "../styles/FavoritesPage.css";

function FavoritesPage() {
  let [recipes, setRecipes] = useState([]);
  let [loading, setLoading] = useState(true);
  let navigate = useNavigate();

  useEffect(() => {
    loadFavorites();

    function reloadFavorites() {
      loadFavorites();
    }

    window.addEventListener("favoritesChanged", reloadFavorites);

    return () => {
      window.removeEventListener("favoritesChanged", reloadFavorites);
    };
  }, []);

  async function loadFavorites() {
    let loggedUser = localStorage.getItem("loggedUser");

    if (!loggedUser) {
      setRecipes([]);
      setLoading(false);
      return;
    }

    let user = JSON.parse(loggedUser);

    try {
      setLoading(true);

      let response = await fetch(
        "http://localhost:5000/api/ulubione/uzytkownik/" + user.id
      );
      let data = await response.json();

      if (Array.isArray(data)) {
        setRecipes(data);
      } else {
        setRecipes([]);
      }

      setLoading(false);
    } catch (error) {
      console.log(error);
      setRecipes([]);
      setLoading(false);
    }
  }

  function renderStars(value) {
    let rating = Math.round(value || 0);
    let stars = [];

    for (let i = 1; i <= 5; i++) {
      stars.push(
        <span key={i} className={i <= rating ? "star filled" : "star"}>
          {i <= rating ? "★" : "☆"}
        </span>
      );
    }

    return stars;
  }

  return (
    <div className="app">
      <Navbar />

      <main className="favorites-page">
        <section className="favorites-hero">
          <div className="container">
            <h1>Twoje ulubione przepisy</h1>
            <p>Zapisane przepisy, do których możesz wrócić w każdej chwili.</p>
          </div>
        </section>

        <section className="section">
          <div className="container">
            {loading ? (
              <p>Ładowanie ulubionych...</p>
            ) : recipes.length === 0 ? (
              <div className="favorites-empty">
                <h3>Nie masz jeszcze ulubionych przepisów</h3>
                <p>
                  Kliknij serduszko przy przepisie, aby dodać go do ulubionych.
                </p>
              </div>
            ) : (
              <div className="favorites-grid">
                {recipes.map((recipe) => (
                  <div className="favorite-card" key={recipe.api_przepis_id}>
                    <div className="favorite-card-image-box">
                      <FavoriteButton recipe={recipe} />
                      <img src={recipe.obrazek} alt={recipe.tytul} />
                    </div>

                    <div className="favorite-card-body">
                      <span className="favorite-badge">
                        {recipe.kategoria || "Przepis"}
                      </span>

                      <h3>{recipe.tytul}</h3>

                      <p className="favorite-country">
                        🌍 {recipe.obszar || "Brak kraju"}
                      </p>

                      <div className="favorite-rating">
                        <div className="recipe-stars">
                          {renderStars(recipe.srednia_ocen)}
                        </div>
                        <span>
                          {recipe.srednia_ocen}/5 ({recipe.liczba_opinii} opinii)
                        </span>
                      </div>

                      <p className="favorite-description">
                        {recipe.instrukcje
                          ? recipe.instrukcje.substring(0, 130) + "..."
                          : "Brak opisu przepisu."}
                      </p>

                      <div className="favorite-actions">
                        {recipe.youtube ? (
                          <a
                            href={recipe.youtube}
                            target="_blank"
                            rel="noreferrer"
                            className="favorite-btn-primary"
                          >
                            Obejrzyj przepis
                          </a>
                        ) : (
                          <button className="favorite-btn-primary disabled" disabled>
                            Brak filmu
                          </button>
                        )}

                        <button
                          className="favorite-btn-secondary"
                          onClick={() => navigate("/przepisy/" + recipe.api_przepis_id)}
                        >
                          Szczegóły przepisu
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </section>
      </main>

      <Footer />
    </div>
  );
}

export default FavoritesPage;
